#!/usr/bin/env python3
"""Multipart upload to R2 via the edgework MPU proxy.

Usage:
  PROXY_BASE=https://... R2_TOKEN=... python3 upload-to-r2.py local.knot models/remote.knot
"""
import sys
import os
import math
import time
import signal
import requests
from pathlib import Path
from contextlib import contextmanager

BASE = os.environ["PROXY_BASE"]
TOKEN = os.environ["R2_TOKEN"]
HEADERS = {"Authorization": f"Bearer {TOKEN}"}
PART_SIZE = 16 * 1024 * 1024  # 16 MiB — fewer round-trips, less exposure to transient 5xx
MAX_RETRIES = 6


class WallClockTimeout(TimeoutError):
    pass


@contextmanager
def _wall_clock_timeout(seconds, label):
    """Bound total request wall time, including slow upload body writes."""
    if not hasattr(signal, "SIGALRM") or seconds is None:
        yield
        return

    def _raise_timeout(_signum, _frame):
        raise WallClockTimeout(f"{label} exceeded {seconds}s wall timeout")

    previous = signal.signal(signal.SIGALRM, _raise_timeout)
    signal.setitimer(signal.ITIMER_REAL, seconds)
    try:
        yield
    finally:
        signal.setitimer(signal.ITIMER_REAL, 0)
        signal.signal(signal.SIGALRM, previous)


def _post_with_retry(
    url,
    *,
    headers,
    params=None,
    data=None,
    json=None,
    timeout=120,
    wall_timeout=None,
    label="request",
):
    """POST with exponential-backoff retry on 5xx and connection errors."""
    delay = 4
    for attempt in range(MAX_RETRIES):
        try:
            with _wall_clock_timeout(wall_timeout or timeout + 90, label):
                r = requests.post(
                    url,
                    headers=headers,
                    params=params,
                    data=data,
                    json=json,
                    timeout=timeout,
                )
            if r.ok:
                return r
            if r.status_code < 500 or attempt == MAX_RETRIES - 1:
                r.raise_for_status()
            print(f"  [{label}] attempt {attempt+1} got {r.status_code}, retry in {delay}s ...", flush=True)
        except (requests.exceptions.ConnectionError, requests.exceptions.Timeout, WallClockTimeout) as exc:
            if attempt == MAX_RETRIES - 1:
                raise
            print(f"  [{label}] attempt {attempt+1} transport timeout/error ({exc}), retry in {delay}s ...", flush=True)
        time.sleep(delay)
        delay = min(delay * 2, 60)
    raise RuntimeError(f"{label} failed after {MAX_RETRIES} attempts")


def upload(local_path: str, r2_key: str) -> None:
    p = Path(local_path)
    size = p.stat().st_size
    total_parts = math.ceil(size / PART_SIZE)
    print(f"[upload] {r2_key} ({size / 1024 / 1024:.1f} MB, {total_parts} parts)", flush=True)

    r = _post_with_retry(f"{BASE}/{r2_key}/mpu-create", headers=HEADERS, json={}, timeout=30, label="mpu-create")
    upload_id = r.json()["uploadId"]
    print(f"  uploadId: {upload_id}", flush=True)

    parts = []
    with open(p, "rb") as f:
        for i in range(1, total_parts + 1):
            chunk = f.read(PART_SIZE)
            print(f"  part {i}/{total_parts} start", flush=True)
            r2 = _post_with_retry(
                f"{BASE}/{r2_key}/mpu-part",
                headers={**HEADERS, "Content-Type": "application/octet-stream"},
                params={"upload": upload_id, "part": i},
                data=chunk,
                wall_timeout=240,
                label=f"part {i}/{total_parts}",
            )
            resp = r2.json()
            # Strip surrounding quotes — R2 returns ETags with literal quote
            # chars (e.g. '"abc"') but mpu-complete needs the raw hex.
            etag = (resp.get("etag") or r2.headers.get("ETag", "")).strip('"')
            part_num = resp.get("partNumber") or i
            parts.append({"partNumber": part_num, "etag": etag})
            print(f"  part {i}/{total_parts} done", flush=True)

    parts.sort(key=lambda x: x["partNumber"])
    print(f"  completing with {len(parts)} parts, first etag={parts[0]['etag']!r}", flush=True)
    r3 = _post_with_retry(
        f"{BASE}/{r2_key}/mpu-complete",
        headers=HEADERS,
        json={"uploadId": upload_id, "parts": parts},
        timeout=60,
        wall_timeout=180,
        label="mpu-complete",
    )
    if not r3.ok:
        print(f"  mpu-complete {r3.status_code}: {r3.text[:500]}", flush=True)
        r3.raise_for_status()
    result = r3.json()
    print(f"[upload] {r2_key} done — etag={result.get('etag','?')} size={result.get('size','?')}", flush=True)


if __name__ == "__main__":
    if len(sys.argv) < 3:
        print("usage: upload-to-r2.py <local-file> <r2-key>", file=sys.stderr)
        sys.exit(2)
    upload(sys.argv[1], sys.argv[2])
